SourceCode.Declaration:
/// <summary>
/// this class will handle sales order lines split in case transfering partail quantity in voyage
/// </summary>
internal final class ETGITMSalesLineSplitOut
{
    SalesLine callerSalesLine;
    SalesQty splitQty;
    ITMId shipId;

    TradeLineNumber newLineNumber;
    InventTransId   inventTransId;

    ETGOTMSalesTableFormDeliverySchedule salesTableForm_DeliverySchedule;
    SalesLine salesLine;
}

Method.Source:
private void createNewSalesLine()
{
    SalesLine tmp;

    NumberSeq numberSeq;

    ETGOTMSalesLineWritePreSuperInputContract     inputContractPre = ETGOTMSalesLineWritePreSuperInputContract::construct();
    ETGOTMSalesLineWritePreSuperOutputContract    outputContractPre;
    ETGOTMSalesLineWritePostSuperInputContract    inputContractPost = ETGOTMSalesLineWritePostSuperInputContract::construct();
    ETGOTMSalesLineWritePostSuperOutputContract   outputContractPost;

    //BP Deviation Documented
    tmp.setTmp();
    tmp.setTmpData(salesLine);
    select maxOf(LineNum) from tmp;
    if (salesLine.LineNum < tmp.LineNum)
    {
        salesLine.LineNum = -salesLine.LineNum;
    }
    else
    {
        salesLine.LineNum = 0;
    }

    salesTableForm_DeliverySchedule.salesLine_InitValue(salesLine);

    SalesLine salesLineMax;

    newLineNumber = newLineNumber + 1;

    salesLine.LineNum = newLineNumber;
    salesLine.SalesQty = splitQty;
    salesLine.QtyOrdered = salesLine.calcQtyOrdered();
    salesLine.RemainSalesPhysical = splitQty;
    salesLine.RemainInventPhysical = salesLine.calcQtyOrdered(salesLine.RemainSalesPhysical);
    salesLine.RemainSalesFinancial = 0;
    salesLine.LineAmount = salesLine.calcLineAmount();
    salesLine.ETGITMId = shipId;

    if (ETGOTMITMPurchLineSplitCleanAutoDimFlight::instance().isEnabled())
    {
        salesLine.InventDimId = this.cleanUpAutoInventoryDimension(salesLine.inventTable(), salesLine.inventDim()).inventDimId;
    }

    if (salesLine.validateWrite() && salesTableForm_DeliverySchedule.salesLine_ValidateWrite(salesLine, salesLine.inventDim()))
    {
        inputContractPre.parmSalesLine(salesLine);
        inputContractPre.parmSalesTable(salesLine.salesTable());

        numberSeq = NumberSeq::newGetNum(InventParameters::numRefInventTransId());
        salesLine.InventTransId = numberSeq.num();

        salesLine.InterCompanyInventTransId = '';

        salesLine.SourceDocumentLine = (select maxof(RecId) from sourceDocumentLine).RecId + 1;

        SalesLine salesLineLineNum;

        select maxof(LINECREATIONSEQUENCENUMBER) from salesLineLineNum
        where salesLineLineNum.SalesId == callerSalesLine.SalesId
            && salesLineLineNum.DataAreaId == callerSalesLine.DataAreaId;

        salesLine.LINECREATIONSEQUENCENUMBER = salesLineLineNum.LINECREATIONSEQUENCENUMBER + 1;
        salesLine.doInsert();

        newLineNumber = salesLine.LineNum;
    }
}

internal TradeLineNumber parmNewLineNumber(TradeLineNumber _newLineNumber = newLineNumber)
{
    newLineNumber = _newLineNumber;
    return newLineNumber;
}

internal InventTransId parmInventTransId(InventTransId _inventTransId = inventTransId)
{
    inventTransId = _inventTransId;
    return inventTransId;
}

private SalesLine parmSalesLine(SalesLine _salesLine = callerSalesLine)
{
    callerSalesLine = _salesLine;
    return callerSalesLine;
}

private ITMId parmShipId(ITMId _shipId = shipId)
{
    shipId = _shipId;
    return shipId;
}

private SalesQty parmSplitQty(SalesQty _splitQty = splitQty)
{
    splitQty = _splitQty;
    return splitQty;
}

internal void run()
{
    if (callerSalesLine.isInterCompanyOrder() && ETGOTMStopSplitIntercompanyLineFlight::instance().isEnabled())
    {
        throw error(strFmt("@InboundTransportationManagement:ITMStopSplitIntercompanySalesLine", callerSalesLine.LineNum, callerSalesLine.SalesId));
    }

    ttsBegin;

    ITMTTSTable::createTTSOutETG();

    this.moveCallerToLast();
    this.initSalesTableForm();
    this.updateCallerSalesLine();
    this.createNewSalesLine();
    this.updateDeliverySchedule();

    ITMTTSTable::deleteTTSOutETG();

    ttsCommit;
}

private InventDim cleanUpAutoInventoryDimension(InventTable _inventTable, InventDim _inventDim)
{
    boolean findOrCreateInventDim = false;
    InventDim ret = _inventDim;

    if (_inventDim.inventBatchId && _inventTable.BatchNumGroupId)
    {
        InventNumGroup batchNumGroup = InventNumGroup::find(_inventTable.BatchNumGroupId);
        if (!batchNumGroup.PhysicalUpdate && !batchNumGroup.ManualAllocation && !batchNumGroup.OnlyInventTransaction)
        {
            _inventDim.inventBatchId = '';
            findOrCreateInventDim = true;
        }
    }

    if (_inventDim.inventSerialId && _inventTable.SerialNumGroupId)
    {
        InventNumGroup serialNumGroup = InventNumGroup::find(_inventTable.SerialNumGroupId);
        if (!serialNumGroup.PhysicalUpdate && !serialNumGroup.ManualAllocation && !serialNumGroup.OnlyInventTransaction)
        {
            _inventDim.inventSerialId = '';
            findOrCreateInventDim = true;
        }
    }

    if (findOrCreateInventDim)
    {
        ret = InventDim::findOrCreate(_inventDim);
    }

    return ret;
}

private void moveCallerToLast()
{
    SalesLine salesLineLineNum;

    select maxof(LineNum) from salesLineLineNum 
        where salesLineLineNum.SalesId == callerSalesLine.SalesId
            && salesLineLineNum.DataAreaId == callerSalesLine.DataAreaId;

    newLineNumber = salesLineLineNum.LineNum;
}

private void updateCallerSalesLine()
{
    ETGOTMSalesLineWritePreSuperInputContract     inputContractPre = ETGOTMSalesLineWritePreSuperInputContract::construct();
    ETGOTMSalesLineWritePreSuperInputContract    outputContractPre;
    ETGOTMSalesLineWritePreSuperInputContract    inputContractPost = ETGOTMSalesLineWritePreSuperInputContract::construct();
    ETGOTMSalesLineWritePreSuperInputContract   outputContractPost;

    if (callerSalesLine.LineDeliveryType == LineDeliveryType::OrderLine)
    {
        select forUpdate salesLine;
    }
    else
    {
        select forUpdate salesLine
            where salesLine.InventTransId == callerSalesLine.InventTransId;
    }

    salesLine.SalesQty -= splitQty;
    salesLine.QtyOrdered = salesLine.calcQtyOrdered();
    salesLine.RemainSalesPhysical -= splitQty;
    salesLine.RemainInventPhysical = salesLine.calcQtyOrdered(salesLine. RemainSalesPhysical);
    salesLine.LineAmount = salesLine.calcLineAmount();
    if (salesLine.validateWrite() && salesTableForm_DeliverySchedule.salesLine_ValidateWrite(salesLine, salesLine.inventDim()))
    {
        inputContractPre.parmSalesLine(salesLine);
        inputContractPre.parmSalesTable(salesLine.salesTable());
        salesLine.doUpdate();
    }
}

private void updateDeliverySchedule()
{
    List newScheduleLines = new List(Types::Container);

    while select salesLine
    {
        newScheduleLines.addEnd([salesLine]);
    }

    SalesTableForm_DeliverySchedule::closeOkServer(callerSalesLine,
        newScheduleLines.pack(),
        DlvScheduleMarkupConversionMode::Split);
}

private server static ETGITMSalesLineSplitOut construct()
{
    return new ETGITMSalesLineSplitOut();
}

internal server static ETGITMSalesLineSplitOut newSalesLineSplit(
    SalesLine _salesLine,
    SalesQty _splitQty,
    ITMId _shipId)
{
    ETGITMSalesLineSplitOut salesLineSplitHelper = ETGITMSalesLineSplitOut::construct();

    salesLineSplitHelper.parmSalesLine(_salesLine);
    salesLineSplitHelper.parmSplitQty(_splitQty);
    salesLineSplitHelper.parmShipId(_shipId);

    return salesLineSplitHelper;
}
